from typing import List

class Solution:
    def returnToBoundaryCount(self, nums: List[int]) -> int:
        pos = 0  # boundary at 0
        count = 0
        for x in nums:
            pos += x  # moving right by x if x>0, left by -x if x<0 => net change is +x
            if pos == 0:
                count += 1
        return count
```

